module up_down_counter(
    input reset_clk,
    input rst,
    input en,
    input dir,

    output reg [3:0] count
);

always @(posedge reset_clk or posedge rst)
begin
  if (rst)
    count <= 4'b0000;
  else if (en)
  begin
    if (dir)
      count <= count + 1;
    else
      count <= count - 1;
  end
end

endmodule
